"use strict";(self.webpackChunkwaste_management_platform_docs=self.webpackChunkwaste_management_platform_docs||[]).push([[5418],{930:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/en/blog/welcome","editUrl":"https://github.com/waste-management/waste-management-platform-docs/tree/main/blog/2024-01-15-welcome.md","source":"@site/blog/2024-01-15-welcome.md","title":"Bienvenido a la Plataforma de Gesti\xf3n de Residuos","description":"\xa1Bienvenido a la Plataforma de Gesti\xf3n de Residuos! Estamos emocionados de presentarte una soluci\xf3n integral que revolucionar\xe1 la forma en que gestionas los residuos en tu organizaci\xf3n.","date":"2024-01-15T00:00:00.000Z","tags":[{"inline":true,"label":"welcome","permalink":"/en/blog/tags/welcome"},{"inline":true,"label":"platform","permalink":"/en/blog/tags/platform"},{"inline":true,"label":"waste-management","permalink":"/en/blog/tags/waste-management"}],"readingTime":1.62,"hasTruncateMarker":true,"authors":[{"name":"Administrador","title":"Equipo de Documentaci\xf3n","url":"https://waste-management-platform.com","imageURL":"https://waste-management-platform.com/img/team/admin.jpg","key":"admin","page":null}],"frontMatter":{"slug":"welcome","title":"Bienvenido a la Plataforma de Gesti\xf3n de Residuos","authors":["admin"],"tags":["welcome","platform","waste-management"]},"unlisted":false},"content":"\x3c!-- truncate --\x3e\\n\\n\xa1Bienvenido a la Plataforma de Gesti\xf3n de Residuos! Estamos emocionados de presentarte una soluci\xf3n integral que revolucionar\xe1 la forma en que gestionas los residuos en tu organizaci\xf3n.\\n\\n## \xbfQu\xe9 es la Plataforma de Gesti\xf3n de Residuos?\\n\\nNuestra plataforma es un ecosistema completo que conecta a todos los actores involucrados en la cadena de valor de los residuos:\\n\\n- **Generadores de residuos** (empresas, industrias, instituciones)\\n- **Gestores y operadores log\xedsticos** (empresas de recolecci\xf3n, tratamiento, almacenamiento)\\n- **Operadores de campo** (recolectores, supervisores, conductores)\\n\\n## Caracter\xedsticas Principales\\n\\n### \ud83d\udcf1 App M\xf3vil de Recolecci\xf3n\\n- Gesti\xf3n de rutas optimizadas\\n- Seguimiento en tiempo real\\n- Captura de datos offline\\n- Sincronizaci\xf3n autom\xe1tica\\n\\n### \ud83d\udcbb Plataforma Web para Gestores\\n- Dashboard ejecutivo completo\\n- Gesti\xf3n de flota y operaciones\\n- An\xe1lisis de datos avanzado\\n- Reportes personalizables\\n\\n### \ud83c\udf10 Portal Web para Generadores\\n- Solicitud de servicios f\xe1cil\\n- Seguimiento en tiempo real\\n- Gesti\xf3n de facturaci\xf3n\\n- An\xe1lisis de costos\\n\\n## Beneficios de la Plataforma\\n\\n### Para Generadores de Residuos\\n- \u2705 Reducci\xf3n de costos operativos\\n- \u2705 Mejora en la trazabilidad de residuos\\n- \u2705 Cumplimiento normativo simplificado\\n- \u2705 Acceso a una red de gestores certificados\\n\\n### Para Gestores y Operadores\\n- \u2705 Optimizaci\xf3n de rutas y recursos\\n- \u2705 Mejora en la eficiencia operativa\\n- \u2705 Reducci\xf3n de costos de combustible\\n- \u2705 Mejor planificaci\xf3n y programaci\xf3n\\n\\n### Para el Medio Ambiente\\n- \u2705 Reducci\xf3n de emisiones de CO2\\n- \u2705 Mejor gesti\xf3n de residuos peligrosos\\n- \u2705 Incremento en las tasas de reciclaje\\n- \u2705 Trazabilidad completa del ciclo de vida\\n\\n## Pr\xf3ximos Pasos\\n\\n1. **[Configuraci\xf3n inicial](/docs/guides/getting-started)** - Aprende a configurar tu cuenta\\n2. **[App M\xf3vil](/docs/app-movil/intro)** - Descubre la aplicaci\xf3n de recolecci\xf3n\\n3. **[Plataforma Web Gestores](/docs/web-gestores/intro)** - Explora el dashboard de gesti\xf3n\\n4. **[Portal Generadores](/docs/web-generadores/intro)** - Conoce el portal de servicios\\n\\n## Soporte y Ayuda\\n\\n- \ud83d\udcda **[Centro de Ayuda](/docs/help/centro-ayuda)** - Encuentra respuestas a preguntas frecuentes\\n- \ud83d\udcac **[Contacto](/docs/help/contacto)** - Obt\xe9n soporte t\xe9cnico personalizado\\n- \ud83d\udd27 **[Estado del Sistema](/docs/help/estado-sistema)** - Monitorea el estado de la plataforma\\n\\n---\\n\\n\xbfListo para comenzar? Te recomendamos empezar con la [gu\xeda de configuraci\xf3n inicial](/docs/guides/getting-started) para configurar tu cuenta y familiarizarte con la plataforma."}]}}')}}]);